head.script:
//hidden
scwin.txt_eqModelCd             = "0";
scwin.txt_eqLupCond             = "0";
scwin.txt_eqClsCd               = "0";
scwin.txt_retrieveYn            = "0";
scwin.txt_saveType              = "";
scwin.txt_eqModelCdValChk       = "";
scwin.txt_rowDelStat            = "";
scwin.txt_countRow              = "0";
scwin.txt_modelCodeEqCls        = "";
scwin.txt_modelCodeEqClss       = "";
scwin.txt_modelCodeEqKnd        = "";
scwin.hd_eqModelGrpCd           = "";
scwin.pos_eqModel = 0;

scwin.vEqClsCd = "";

scwin.vEqClssCdStatus = "";
scwin.vEqKndCdStatus = "";
