scwin.acb_eqClssCd_changed = false;
scwin.acb_eqClsCd_changed = false;

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "ZZ201", compID : "acb_eqClsCd,acb_lux_eqClsCd"},
        { grpCd : "RC801", compID : "acb_rentcarCartypeCntyCd"},
        { grpCd : "ZZ609", compID : "acb_makerCd"},
        { grpCd : "RC802", compID : "acb_eqModelPurpsCd"},
        { grpCd : "RC804", compID : "acb_eqModelGrdCd"},
        { grpCd : "ZZ207", compID : "acb_engdispCd"},
        { grpCd : "ZZ507", compID : "acb_seatCnt"},
        { grpCd : "RC805", compID : "acb_eqModelGrbxCd"},
        { grpCd : "ZZ604", compID : "acb_fuelKndCd"},
        { grpCd : "RC270", compID : "acb_vehclGrdCd"},

        //향후 자동세팅 뭐 이런거 할때 사용 예정임 by 송규엽 
        // { grpCd : "ZZ609", compID : "rentMakerCd_Normal", opt : {'range': '3,AA'} },
        // { grpCd : "ZZ609", compID : "MakerCd_Rent", opt : {'range': '3,RC'} },
    ];
    $c.data.setCommonCode(codeOptions);	

    rentMakerCd_Normal.hide();
    MakerCd_Rent.hide();
};

scwin.ondataload = async function(e) {
    let dltStr = "dlt_commonCodeZZ609"; // ZZ609 코드의 dataList
    let dlt = $c.gus.object(dltStr);
    $c.gus.copy(dltStr, "dlt_commonCodeZZ609_1", true); // dlt_commonCodeZZ609_1 으로 dataList 을 복사
    $c.gus.copy(dltStr, "dlt_commonCodeZZ609_2", true);

    let dlt2 = $c.gus.object("dlt_commonCodeZZ609_1"); // 객체화
    let dlt3 = $c.gus.object("dlt_commonCodeZZ609_2"); // 객체화


    // RC 삭제 예정
    $c.data.dataListFilter(dlt2, "fltrCd3 == 'AA'");
    $c.data.dataListFilter(dlt3, "fltrCd3 == 'RC'");
    rentMakerCd_Normal.setNodeSet("data:dlt_commonCodeZZ609_1", "cdNm", "cd"); // selectBox 에 새로운 데이터리스트로 매핑
    MakerCd_Rent.setNodeSet("data:dlt_commonCodeZZ609_2", "cdNm", "cd"); // selectBox 에 새로운 데이터리스트로 매핑

}



scwin.onUdcCompleted = async function() {

    scwin.f_ContentsDisable();

    $c.gus.cfDisableBtn([b_Cancel, b_Update, btn_save]);

    $c.gus.cfEnableObj(acb_eqNrmCd, false); // 장비규격코드


	scwin.f_eqCodeList(sbm_eqClssCd, "ZZ202", "");
	scwin.f_eqCodeList(sbm_eqKndCd, "ZZ210", "");
	scwin.f_eqCodeList(sbm_eqNrmCd, "ZZ208", "");

    ed_qryCntn.focus();
};


//-------------------------------------------------------------------------
// 장비모델목록 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {  
    scwin.f_ContentsDisable();
    scwin.txt_saveType = 2; 

    scwin.txt_qryCntn = (ed_qryCntn.getValue()).trimAll();

    dma_search.set("eqClsCd", scwin.txt_eqClsCd);
    dma_search.set("qryCond", scwin.txt_eqLupCond);
    dma_search.set("qryCntn", ed_qryCntn.getValue());

    $c.sbm.execute(sbm_searchEqmodel);

};

//-------------------------------------------------------------------------
// 항목 Enable
//-------------------------------------------------------------------------
scwin.f_ContentsEnable = function () {

    $c.gus.cfEnableKeyData();
    // $c.gus.cfEnableObj(ed_eqModelEngNm, true);
    // $c.gus.cfEnableObj(acb_rentcarCartypeCntyCd, true);
    // $c.gus.cfEnableObj(eqModelVehclCls_search, true);
    // $c.gus.cfEnableObj(ed_eqModelVehclClsCd, true);
    // $c.gus.cfEnableObj(ed_eqModelVehclClsNm, true);

    $c.gus.cfEnableObj(acb_homprdYn, true); // 국산여부
    $c.gus.cfEnableObj(acb_makerCd, true); // 제조사코드
    $c.gus.cfEnableObj(rentMakerCd_Normal, true); // 제조사코드
    $c.gus.cfEnableObj(MakerCd_Rent, true); // 제조사코드
