    $c.gus.cfEnableObj(ed_eqModelEngNm, true); // 모델영문명

    $c.gus.cfEnableObj(ed_rentacarEqModelCd, false); 
    $c.gus.cfEnableObj(cbx_chkEngdispYn, true); 
    $c.gus.cfEnableObj(cbx_chkSeatYn, true); 
    $c.gus.cfEnableObj(acb_vehclGrdCd, true); // 차량등급코드
