    //$c.gus.cfEnableObj(eqModelGrpNm, true);

    $c.gus.cfEnableObj(ed_asetKndCd, true); 
    $c.gus.cfEnableObj(ed_asetKndNm, true); 
    $c.gus.cfEnableObj(aset_search, true);

}

