    $c.gus.cfEnableObj(lendTrfGrp_search, false); // 대여요율팝업이미지
    $c.gus.cfEnableObj(ed_lendTrfGrpCd2, false); // 대여요율 코드 (제주도)
    $c.gus.cfEnableObj(ed_lendTrfGrpNm2, false); // 대여요율명(제주도)
    $c.gus.cfEnableObj(lendTrfGrp_search2, false); //대여요율 팝업이미지(제주도)
