//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = async function() {
    scwin.txt_saveType = 0; // 0:신규, 1:수정, 2:조회
    scwin.f_ContentsEnable();

    scwin.f_AddRow(); // 행추가

    let vEqClsCd = acb_eqClsCd.getValue(); // 장비구분
    // await scwin.f_eqCodeList(sbm_eqClssCd, "ZZ202", vEqClsCd);


    acb_eqClsCd.setSelectedIndex(0);
    acb_fuelKndCd.setSelectedIndex(0);
    acb_engdispCd.setSelectedIndex(-1);
    acb_homprdYn.setSelectedIndex(-1);
    acb_seatCnt.setSelectedIndex(-1);
    acb_eqClssCd.setValue("TG");
    acb_eqKndCd.setValue("TG");

