    $c.gus.cfEnableObj(ed_eqModelNm, true); // 모델명
    $c.gus.cfEnableObj(acb_engdispCd, false); // 배기량코드
    $c.gus.cfEnableObj(acb_homprdYn, false); // 국산여부
    $c.gus.cfEnableObj(acb_seatCnt, false); // 좌석수
    $c.gus.cfEnableObj(acb_eqKndCd, true);
    $c.gus.cfEnableObj(acb_eqNrmCd, true);
    $c.gus.cfEnableObj(acb_eqClssCd, true);
    $c.gus.cfEnableObj(acb_eqClsCd, true);
    $c.gus.cfEnableObj(ed_eqModelEngNm, true);
    $c.gus.cfEnableObj(acb_vehclGrdCd, true);
    $c.gus.cfEnableObj(acb_makerCd, true);
    $c.gus.cfEnableObj(rentMakerCd_Normal, true); // 제조사코드
    $c.gus.cfEnableObj(MakerCd_Rent, true); // 제조사코드

    $c.gus.cfEnableObj(acb_fuelKndCd, true);
    $c.gus.cfEnableObj(ed_lendTrfGrpCd, false);
    $c.gus.cfEnableObj(ed_lendTrfGrpNm, false);
    $c.gus.cfEnableObj(lendTrfGrp_search, false);
    $c.gus.cfEnableObj(ed_lendTrfGrpCd2, false);
    $c.gus.cfEnableObj(ed_lendTrfGrpNm2, false);
    $c.gus.cfEnableObj(lendTrfGrp_search2, false);
    $c.gus.cfEnableObj(ed_asetKndCd, false); 
    $c.gus.cfEnableObj(ed_asetKndNm, false); 
    $c.gus.cfEnableObj(aset_search, false);

    //$c.gus.cfEnableObj(eqModelGrpCd, false);  //장비모델그룹코드
    $c.gus.cfEnableObj(acb_rentcarCartypeCntyCd, false); //렌터카차종국가코드
    $c.gus.cfEnableObj(acb_eqModelPurpsCd, false); //장비모델용도코드
    $c.gus.cfEnableObj(ed_eqModelVehclClsCd, false); //장비모델차량구분코드
    $c.gus.cfEnableObj(ed_eqModelVehclClsNm, false); //장비모델차량구분코드
    $c.gus.cfEnableObj(acb_eqModelGrbxCd, false); //장비모델변속기코드
    // $c.gus.cfEnableObj(eqModelGrpYn, false); //장비모델그룹여부코드
    // $c.gus.cfEnableObj(intrntPrtnModelNm, false); //인터넷출력모델명
