};

//-------------------------------------------------------------------------
// 장비모델 수정
//-------------------------------------------------------------------------
scwin.f_Update = function () {
    scwin.vEqClssCdStatus = "U";
    scwin.vEqKndCdStatus = "U";
    scwin.vEqNrmCdStatus = "U";
    scwin.txt_saveType = 1;

    let vEqClsCode = acb_eqClsCd.getValue(); // 장비구분
    scwin.f_ContentsEnable();
    $c.gus.cfEnableObj(ed_eqModelCd, false); // 장비모델코드

    if(vEqClsCode=="RV" || vEqClsCode=="TV"){
        $c.gus.cfEnableObj(acb_eqKndCd, false); // 장비종류코드
        //$c.gus.cfEnableObj(acb_eqNrmCd, false); // 장비규격코드
    }else{
        $c.gus.cfEnableObj(acb_eqKndCd, true); // 장비종류코드
        $c.gus.cfEnableObj(acb_eqNrmCd, true); // 장비규격코드
    }

    if(vEqClsCode!="RV"){
        // ed_lendTrfGrpCd.setDisabled(true);
        // ed_lendTrfGrpNm.setDisabled(true);
        // lendTrfGrp_search.setDisabled(true);
        // ed_lendTrfGrpCd2.setDisabled(true);
        // ed_lendTrfGrpNm2.setDisabled(true);
        // lendTrfGrp_search2.setDisabled(true);
    //			eqModelGrpCd_search.Enable = false;
    //			eqModelGrpNm.setDisabled(true);
    //			eqModelGrpCd.Enable = false;
        $c.gus.cfEnableObj(ed_rentacarEqModelCd, false); 
        $c.gus.cfEnableObj(cbx_chkEngdispYn, false); 
        $c.gus.cfEnableObj(cbx_chkSeatYn, false);
        $c.gus.cfEnableObj(ed_asetKndCd, false); 
        $c.gus.cfEnableObj(ed_asetKndNm, false); 
        $c.gus.cfEnableObj(aset_search, false);


    }else{
        // ed_lendTrfGrpCd.setDisabled(false);
        // ed_lendTrfGrpNm.setDisabled(false);
        // lendTrfGrp_search.setDisabled(false);
        // ed_lendTrfGrpCd2.setDisabled(false);
        // ed_lendTrfGrpNm2.setDisabled(false);
        // lendTrfGrp_search2.setDisabled(false);		
    //			eqModelGrpCd_search.Enable = true;
    //			eqModelGrpNm.setDisabled(false);
    //			eqModelGrpCd.Enable = true;
        $c.gus.cfEnableObj(ed_rentacarEqModelCd, true);
        $c.gus.cfEnableObj(cbx_chkEngdispYn, true);
        $c.gus.cfEnableObj(cbx_chkSeatYn, true);
        $c.gus.cfEnableObj(ed_asetKndCd, false); 
        $c.gus.cfEnableObj(ed_asetKndNm, false); 
        $c.gus.cfEnableObj(aset_search, false);   
        }

    $c.gus.cfDisableBtn([b_Create, b_Update]);
}

//-------------------------------------------------------------------------
// 장비모델 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function () {
// 취소 확인

    scwin.vEqClssCdStatus = "Cancel";
    scwin.vEqKndCdStatus = "Cancel";
    scwin.vEqNrmCdStatus = "Cancel";

    if(ds_eqmodel.getRowPosition()>=0){
        $c.data.undoAll(ds_eqmodel);
        let rowIndex = ds_eqmodel.getRowPosition();
        // let vEqClsCd = ds_eqmodel.getCellData(rowIndex, "eqClsCd");
        // let vEqClssCd = ds_eqmodel.getCellData(rowIndex, "eqClssCd");
        // let vEqKndCd = ds_eqmodel.getCellData(rowIndex, "eqKndCd");
        debugger;
        scwin.f_eqCodeList(sbm_eqClssCd, "ZZ202", scwin.vEqClsCd);
        scwin.f_eqCodeList(sbm_eqKndCd, "ZZ210", scwin.vEqClssCd);
        scwin.f_eqCodeList(sbm_eqNrmCd, "ZZ208", scwin.vEqKndCd);

        // ds_eqmodel.reform();
        scwin.txt_saveType = "";	

        ed_lendTrfGrpNm.setValue("");
        ed_lendTrfGrpNm2.setValue("");

        ed_eqModelCd.setMandatory(false);
        // ed_eqModelCd.validExp="";

        scwin.f_ContentsDisable();

        $c.gus.cfDisableBtn([b_Cancel,btn_save]);
    } 	

    // $c.data.undoAll로 인해 setFocusedCell 처리
    let rowIndex = ds_eqmodel.getRowPosition();
    if (rowIndex == null){
        rowIndex = ds_eqmodel.getRowCount() -1;
    }
    gr_eqmodel.setFocusedCell(rowIndex, 0);
}

//-------------------------------------------------------------------------
// 장비모델 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = function () {

    scwin.txt_saveType = "3";   // 수정인경우(1:신규, 2: 수정, 3: 삭제)	
    scwin.f_delRow();
    $c.gus.cfEnableBtnOnly([btn_save]);
}



//-------------------------------------------------------------------------
// 장비모델 행추가
//-------------------------------------------------------------------------
scwin.f_AddRow = function () {
    let newIndex = ds_eqmodel.insertRow();
    gr_eqmodel.setFocusedCell(newIndex, "eqModelCd");
    ds_eqmodel.setRowPosition(newIndex,true);
    scwin.txt_rowDelStat = "0";
}



//-------------------------------------------------------------------------
// 행삭제
//-------------------------------------------------------------------------
scwin.f_delRow = function () {
    ds_eqmodel.deleteRow(ds_eqmodel.getRowPosition())
    scwin.txt_rowDelStat = "1";
}

//-------------------------------------------------------------------------
// 행취소
//-------------------------------------------------------------------------
scwin.f_Undo = function () {

    $c.data.undoAll(ds_eqmodel);
    scwin.txt_rowDelStat = "2";

}


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {

    // 장비모델ID가 유효하지 않은데도 저장하는 경우
    let vEqModelCdValChk = scwin.txt_eqModelCdValChk;
    let vSaveType = scwin.txt_saveType;// 저장타입
    let vRowDelStat = scwin.txt_rowDelStat; //삭제 상태
    let vEqClsCd = acb_eqClsCd.getValue();
    let vRowStatus = ds_eqmodel.getRowStatus(ds_eqmodel.getRowPosition());

    // 필수항목 체크
    let ret = await $c.gus.cfValidate([chkRegistInfo]);
    if(! ret){
        return false;
    }


    // 장비모델코드, 장비모델명 체크 	
    let vEqModelCd = (ed_eqModelCd.getValue()).trimAll();

    if(vRowStatus== 'C'){
        //렌터카 장비모델 중복 체크 	
        if(vEqClsCd=="RV" && vEqModelCdValChk!= "0"){
            await $c.win.alert("렌터카장비모델 중복확인을 하시기 바랍니다.");
            scwin.f_openEqModelCdDup();
            return;
        }	  
    }

    //변경한 데이터가 있는지 체크한다. 	
        if(ds_eqmodel.getModifiedIndex().length > 0==false){
            await $c.win.alert("변경된 사항이 없습니다.");
            return;
        }


    if(await $c.win.confirm("저장하시겠습니까?")==true){
        scwin.pos_eqModel = ds_eqmodel.getRowPosition();
        $c.sbm.execute(sbm_saveEqModel);
    }	
    //$c.gus.cfDisableBtnOnly([bAddRow, bUpdateRow, bDeleteRow]);
}

scwin.f_downExcelSheet = async function () {
    let cntRow = ds_eqmodel.getRowCount();

    if(cntRow!= 0){
        cfrm = await $c.win.confirm("장비모델목록을 EXCEL로 다운로드 받으시겠습니까?");
    if(cfrm){
        let fileName = '장비모델목록';
        let sheetTitle = '물류중기목록';
        await $c.data.downloadGridViewExcel(gr_eqmodel, { fileName: fileName + ".xlsx", sheetName: sheetTitle });
    }
    }else {
    await $c.win.alert(MSG_CM_WRN_002);
    }
}


//-------------------------------------------------------------------------
// 렌터카 장비모델ID 중복확인
//-------------------------------------------------------------------------
scwin.f_openEqModelCdDup = async function () {
    let vEqModelCd = (ed_eqModelCd.getValue()).trimAll();
    if(vEqModelCd=="") {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_002 , ["장비모델코드"]));
        ed_eqModelCd.focus();
        return;
    }

    await udc_rentEqModelListInfo.cfCommonPopUp(
        scwin.udc_rentEqModelListInfo_callBackFunc, 
        vEqModelCd,
        '',
        null,
        null,
        null,
        null,
        null,
        null,
        null,
        null,
        null,
        null,
        "T",
        null,
        null); //  장비모델정보
}

//-------------------------------------------------------------------------
// 팝업결과
//-------------------------------------------------------------------------
scwin.udc_rentEqModelListInfo_callBackFunc = async function(rtnList) {
    if (rtnList > 0) {	
    //장비모델ID 중복체크결과 , 0: 중복없음, 1이상: 중복
        await $c.win.alert($c.data.getMessage(MSG_CM_WRN_011 , ["장비모델코드"]));
        scwin.txt_eqModelCdValChk = "1";
        ed_eqModelCd.focus();
    }else {
        await $c.win.alert("등록가능한 장비모델코드 입니다.");
        //await $c.win.alert($c.data.getMessage(MSG_CM_INF_015 , msgClntDupArr));
        ed_eqModelNm.focus();
        scwin.txt_eqModelCdValChk = "0";
    }
};

scwin.f_eqCodeList = async function(pCodeDataSet, pGrpCd, pUpperCd) {
    //장비코드 Luxe Combo
    let vUpperCode = pUpperCd.trim();
    console.log(vUpperCode)

    pCodeDataSet.action="/cm.zz.RetrieveComboCMD.do?sysCd=EquipmentEBC&queryId=retrieveEqCode&param1=" + pGrpCd + "&param2=" + vUpperCode;

    $c.sbm.execute(pCodeDataSet);
}


