scwin.f_Delete = function () {
    let idx = ds_eqmodel.getRowPosition()
    ds_eqmodel.deleteRow(ds_eqmodel.getRowPosition())
    gr_eqmodel.setFocusedCell(idx, 0);

    $c.gus.cfDisableBtn([b_Create, b_Update, b_Delete]);
}


