scwin.f_openLendTrfInfoPopUp = function(tmpNum) {

    switch(tmpNum) {
        case '01' : 
        udc_lendTrfListInfo.cfCommonPopUp(
            scwin.udc_lendTrfListInfo_callBackFunc, 
            ed_lendTrfGrpCd.getValue(),
            '',
            "T",
            null,
            null,
            "150,180",
            "3,4,5,6,7,8,9,10",
            null,null,null,null,null,null,null,null,null); 
        break;

        case '02' : 
        udc_lendTrfListInfo2.cfCommonPopUp(
            scwin.udc_lendTrfListInfo2_callBackFunc,
             ed_lendTrfGrpCd2.getValue(),
             '',
             "T",
             null,
             null,
             "150,180",
             "3,4,5,6,7,8,9,10",
             null,null,null,null,null,null,null,null,null); 
        break;

        case '03' : 
        udc_asetKndInfo.cfCommonPopUp(
            scwin.udc_asetKndInfo_callBackFunc, 
            ed_asetKndCd.getValue(),
            ed_asetKndNm.getValue(),
            "F",
            null,
            null,
            null,
            null,
            "30,1,1",
            null,null,null,null,null,null,null,null); 

        break;

        default :
            return
    }
}

