//-------------------------------------------------------------------------
// 렌터카용모델코드조합
//-------------------------------------------------------------------------
scwin.f_makeRentacarEqModelCd = async function () {
    ed_rentacarEqModelCd.setValue("");
    let rowIndex = ds_eqmodel.getRowPosition()

    if(acb_eqClsCd.getValue() == 'RV'){
        let vRentcarCartypeCntyCd = "";
        let vMakerCd = "";
        let vEqModelPurpsCd = "";
        let vEqModelVehclClsCd = "";
        let vEqModelGrdCd = "";
        let vEngdispCd = "";
        let vEqModelGrbxCd = "";
        let vSeatCnt = "";
        let vFuelKndCd = "";

        if(cbx_chkEngdispYn.getValue() == '1' && cbx_chkSeatYn.getValue() == '1'){
        await $c.win.alert("배기량 혹은 인승 하나만 적용 가능합니다.");
            return;
        }

        if(cbx_chkEngdispYn.getValue() == '1' && cbx_chkSeatYn.getValue() == '0'){
            vEngdispCd = acb_engdispCd.getValue();
        }
        if(cbx_chkEngdispYn.getValue() == '1' && cbx_chkSeatYn.getValue() == '0'){
            vSeatCnt = acb_seatCnt.getValue();
        }


        vRentcarCartypeCntyCd = acb_rentcarCartypeCntyCd.getValue(); 
        vMakerCd = acb_makerCd.getValue(); 
        vEqModelPurpsCd = acb_eqModelPurpsCd.getValue();
        vEqModelVehclClsCd = ed_eqModelVehclClsCd.getValue(); 
        vEqModelGrdCd = acb_eqModelGrdCd.getValue();
        vEqModelGrbxCd = acb_eqModelGrbxCd.getValue();
        vFuelKndCd = acb_fuelKndCd.getValue();

        let tmp = vRentcarCartypeCntyCd
                                +  vMakerCd
                                +  vEqModelPurpsCd
                                +  vEqModelVehclClsCd
                                +  vEqModelGrdCd
                                +  vEngdispCd
                                +  vSeatCnt
                                +  vEqModelGrbxCd
                                +  vFuelKndCd

        ed_rentacarEqModelCd.setValue(tmp);
    }

}


