scwin.acb_eqClsCd_onviewchange = async function (info) {
    scwin.vEqClssCdStatus = "C";
    scwin.vEqKndCdStatus = "C";
    scwin.vEqNrmCdStatus = "C";
    let curRowIndex = ds_eqmodel.getRowPosition(); // 현재 데이터셋이 가리키는 행
    let vRowStatus = ds_eqmodel.getRowStatus(curRowIndex); // 그 행의 상태

	if(vRowStatus=='C' || vRowStatus=='U' ){  
        let vEqClsCd = acb_eqClsCd.getValue();  // 장비구분
		let vSaveType = scwin.txt_saveType;
        scwin.txt_eqModelCdValChk = "1";  // 장비코드 중복체크 
		if(vRowStatus=='C'){
			ed_eqModelCd.setValue("");
 		}

		if(vEqClsCd.trim()=="LH" || vEqClsCd.trim()=="LS" || vEqClsCd.trim()=="LV"){
			 //향후 자동세팅 뭐 이런거 할때 사용 예정임 by 송규엽 
			acb_makerCd.hide();
            acb_makerCd.unbindRef();
            MakerCd_Rent.hide();
            MakerCd_Rent.unbindRef();
            rentMakerCd_Normal.show();
            rentMakerCd_Normal.setRef("data:ds_eqmodel.makerCd");

			acb_engdispCd.setSelectedIndex(-1);
			acb_homprdYn.setSelectedIndex(-1);
			acb_seatCnt.setSelectedIndex(-1);
			acb_fuelKndCd.setSelectedIndex(1);

            acb_eqKndCd.setDisabled(false);

			$c.gus.cfEnableObj(eqmodelcd_search, false); // 장비모델코드

			$c.gus.cfEnableObj(ed_eqModelCd, false); // 장비모델코드
			$c.gus.cfEnableObj(acb_engdispCd, false); // 배기량
			$c.gus.cfEnableObj(acb_homprdYn, false); // 국산여부
			$c.gus.cfEnableObj(acb_seatCnt, false); // 좌석

			$c.gus.cfEnableObj(ed_lendTrfGrpCd, false); // 대여요율
			$c.gus.cfEnableObj(ed_lendTrfGrpNm, false); // 대여요율명
			$c.gus.cfEnableObj(lendTrfGrp_search, false); //대여요율팝업이미지
			$c.gus.cfEnableObj(ed_lendTrfGrpCd2, false); // 대여요율
			$c.gus.cfEnableObj(ed_lendTrfGrpNm2, false); // 대여요율명
			$c.gus.cfEnableObj(lendTrfGrp_search2, false); //대여요율팝업이미지
			$c.gus.cfEnableObj(ed_asetKndCd, false); 
			$c.gus.cfEnableObj(ed_asetKndNm, false); 
			$c.gus.cfEnableObj(aset_search, false);


//$c.gus.cfEnableObj(eqModelGrpCd_search, false);
//			$c.gus.cfEnableObj(eqModelGrpCd, false); //장비모델그룹코드
			$c.gus.cfEnableObj(acb_rentcarCartypeCntyCd, false); //렌터카차종국가코드
			$c.gus.cfEnableObj(acb_eqModelPurpsCd, false); //장비모델용도코드
			$c.gus.cfEnableObj(ed_eqModelVehclClsCd, false); //장비모델차량구분코드
			$c.gus.cfEnableObj(ed_eqModelVehclClsNm, false); //장비모델차량구분코드
			$c.gus.cfEnableObj(acb_eqModelGrbxCd, false); //장비모델변속기코드
//			$c.gus.cfEnableObj(eqModelGrpYn, false); //장비모델그룹여부코드
//			$c.gus.cfEnableObj(intrntPrtnModelNm, false); //인터넷출력모델명
