//			$c.gus.cfEnableObj(eqModelGrpNm, false);

			$c.gus.cfEnableObj(ed_rentacarEqModelCd, false);
			$c.gus.cfEnableObj(cbx_chkEngdispYn, false);
			$c.gus.cfEnableObj(cbx_chkSeatYn, false);

            ed_eqModelCd.setMandatory(false);
            tbx_eqModelCd.removeClass("req");	
			acb_engdispCd.setMandatory(false);
            tbx_engdispCd.removeClass("req");			
			acb_seatCnt.setMandatory(false);
            tbx_seatCnt.removeClass("req");		
			acb_vehclGrdCd.setMandatory(false);
            tbx_vehclGrdCd.removeClass("req");			
			ed_lendTrfGrpCd.setMandatory(false);
            tbx_lendTrfGrpCd.removeClass("req");			
			acb_fuelKndCd.setMandatory(false);
            tbx_fuelKndCd.removeClass("req");			
			acb_makerCd.setMandatory(false);
            tbx_makerCd.removeClass("req");		
			acb_homprdYn.setMandatory(false);
            tbx_homprdYn.removeClass("req");			
