			 //향후 자동세팅 뭐 이런거 할때 사용 예정임 by 송규엽 
			acb_makerCd.hide();
            acb_makerCd.unbindRef();
            rentMakerCd_Normal.hide();
            rentMakerCd_Normal.unbindRef();
            MakerCd_Rent.show();
            MakerCd_Rent.setRef("data:ds_eqmodel.makerCd")


			acb_engdispCd.setValue("");
			acb_homprdYn.setValue(0);
