scwin.ds_eqmodel_onrowpositionchange = async function (info) {
	let vRowCount = scwin.txt_countRow;
    let newRowIndex = info.newRowIndex;

	if(newRowIndex >0){
		scwin.txt_eqModelCd = ds_eqmodel.getCellData(newRowIndex, "eqModelCd");
		let vEqClsCd = ds_eqmodel.getCellData(ds_eqmodel.getRowPosition(), "eqClsCd");
		let vSaveType = scwin.txt_saveType;
		let vCountRow = scwin.txt_countRow;  // 조회 갯수

		ed_lendTrfGrpCd.setDisabled(true);
		ed_lendTrfGrpNm.setDisabled(true);
		lendTrfGrp_search.setDisabled(true);
		ed_lendTrfGrpCd2.setDisabled(true);
		ed_lendTrfGrpNm2.setDisabled(true);
		lendTrfGrp_search2.setDisabled(true);
		$c.gus.cfEnableObj(ed_rentacarEqModelCd, false); 
		$c.gus.cfEnableObj(cbx_chkEngdispYn, false); 
		$c.gus.cfEnableObj(cbx_chkSeatYn, false); 

        if(newRowIndex<=vRowCount){
            scwin.f_ContentsDisable();
        }
	}
    scwin.f_eqCodeList(sbm_eqClssCd, "ZZ202", scwin.vEqClsCd);
    scwin.f_eqCodeList(sbm_eqKndCd, "ZZ210", scwin.vEqClssCd);
    scwin.f_eqCodeList(sbm_eqNrmCd, "ZZ208", scwin.vEqKndCd);
};

